# --- Session Management Functions ---

# Function to generate a new unique session ID
sub _generate_session_id {
    my $ip_address = $q->remote_addr || 'unknown';
    my $ua_string = $q->user_agent || 'unknown';
    my $random_string = rand() . time() . $$ . $ip_address . $ua_string;
    return sha256_hex($random_string);
}

# Function to get the full path to a session file
sub _get_session_filepath {
    my ($session_id) = @_;
    return File::Spec->catfile($SESSION_DIR, $session_id);
}

# Function to load session data
sub _load_session {
    my ($session_id) = @_;
    my $filepath = _get_session_filepath($session_id);
    my %session_data = ();

    # Create session directory if it doesn't exist
    unless (-d $SESSION_DIR) {
        mkdir $SESSION_DIR or die "Cannot create session directory $SESSION_DIR: $!";
    }

    if (-f $filepath) {
        my $fh;
        open($fh, "<", $filepath) or warn "Cannot open session file $filepath for reading: $!";
