                return {};
            }
        }
    }
    return \%session_data;
}

# Function to save session data
sub _save_session {
    my ($session_id, $session_ref) = @_;
    my $filepath = _get_session_filepath($session_id);

    # Update last access time
    $session_ref->{_last_access} = time();

