# Function to perform garbage collection on expired sessions
sub _gc_sessions {
    return unless rand() < $SESSION_GC_PROBABILITY;

    opendir my $dh, $SESSION_DIR or return; # Die if directory not found

    my $now = time();
    while (my $filename = readdir $dh) {
        next if $filename eq '.' || $filename eq '..';
        my $filepath = File::Spec->catfile($SESSION_DIR, $filename);

        # Skip if not a regular file or if it's currently locked (in use)
        next unless -f $filepath;

