# Main session handler function
sub start_session {
    my %session = ();
    my $session_id = $q->cookie($SESSION_COOKIE_NAME);

    _gc_sessions(); # Run garbage collection with a certain probability

    if ($session_id) {
        # Attempt to load existing session
